      OR UPPER(P.EXT_PAY_ID) LIKE '%' || UPPER(#{detailCondition.keyword}) || '%')


    AND TRIM(P.PAY_MTHD_CD) = #{detailCondition.payMthdCd}


    AND TRIM(P.PAY_STAT_CD) = #{detailCondition.payStatCd}

